import fs from 'fs/promises';
import path from 'path';
import { getGenerateContentEndpoint } from './google-auth.js';

/** Narration script + per-segment scene prompts generated by Gemini. */
export interface StoryScript {
  narrationScript: string;
  scenes: { prompt: string }[];
  caption: string;
}

function mimeTypeFor(imagePath: string): string {
  const ext = path.extname(imagePath).toLowerCase();
  if (ext === '.png') return 'image/png';
  if (ext === '.webp') return 'image/webp';
  return 'image/jpeg';
}

/**
 * Use Gemini to turn the user's pasted text (and reference images) into a
 * story: a narration script paced for the target length, plus one cinematic
 * scene prompt per 8-second Veo segment.
 */
export async function generateStory(opts: {
  storyText: string;
  imagePaths: string[];
  targetSeconds: number;
  segmentCount: number;
}): Promise<StoryScript> {
  const { storyText, imagePaths, targetSeconds, segmentCount } = opts;

  // Slightly under natural speech rate (~140 wpm) so the voiceover lands
  // inside the video; the mux time-scales any small overrun.
  const narrationWords = Math.floor((targetSeconds * 140) / 60);

  const imageNote =
    imagePaths.length > 0
      ? `\nThe user also attached ${imagePaths.length} reference image(s), shown above. ` +
        `Weave their subjects, settings, and mood into the story. Some video segments ` +
        `will be seeded directly from these images, so the corresponding scenes should ` +
        `feel continuous with them.`
      : '';

  const prompt = `You are creating a ${targetSeconds}-second vertical (9:16) social media video. Given the source text below, create:

1. A narration script of between ${Math.floor(narrationWords * 0.9)} and ${narrationWords} words \
— long enough to fill nearly all ${targetSeconds} seconds of the video with natural speech, but it must not run over. It should tell an \
informative, objective, and realistic story drawn from the source text, mimicking the style of a serious \
journalistic, educational, or historical documentary (e.g., PBS Frontline or BBC Horizon).
- Do NOT use generic intro/outro phrases, promotional hooks, or cinematic cliches (e.g., "Join us...", "In this video...", "Discover the secrets of...", "Let's explore...").
- Prefer to convey concrete information, key facts, specific dates, names of real people, places, or organizations, and actual statistics/numbers from the source text.
- Prioritize accuracy, objectivity, and informativeness over dramatic narrative or creative embellishment. Avoid vague summaries or simplifying details.
- CRITICAL: The narration will be read aloud by a text-to-speech model with strict content filters. \
The script MUST NOT mention: alcohol, alcoholism, drugs, drinking, drunkenness, guns, firearms, weapons, \
violence, aggression, injuries, death, crime, theft, sexual content, or any dangerous/harmful activities. \
If the source text covers these topics, either omit them entirely or reframe them in a safe, positive way \
(e.g., instead of 'alcoholism is common', say 'cultural customs may differ from what you expect').

2. Exactly ${segmentCount} scene descriptions for 8-second video segments that flow as \
one continuous story. Each scene should visually illustrate part of the narration with \
cinematic motion. Describe camera movements, subjects, and visual style. The scenes must \
be purely visual with ambient sound only: no dialogue, speech, singing, or quoted text, \
and no on-screen text or labels. Keep imagery symbolic and family-friendly — avoid \
violence, weapons, suffering.
- CRITICAL: Every scene MUST place its subject(s) against a solid, uniform bright green \
chroma key screen (#00FF00). Describe only subjects and foreground action — NEVER describe \
environments, locations, backgrounds, skies, landscapes, rooms, or scenery of any kind.
- CRITICAL: Each scene must be ONE single continuous shot with no cuts, no transitions, \
no fades, no dissolves, and no scene changes within the segment. While avoiding identifiable real or historical people in the prompts to pass \
video safety filters, describe stylized representations or visually abstract depictions of the events/concepts \
mentioned in the narration.${imageNote}

3. A TikTok/social media caption (max 300 characters including hashtags). It should be attention-grabbing, \
informative, and include 3-5 relevant hashtags. Do NOT use generic hashtags like #fyp or #viral — use \
topic-specific ones drawn from the content.

Source text:
${storyText.slice(0, 6000)}

Return ONLY valid JSON (no markdown fences) with this structure:
{
  "narrationScript": "The full narration text...",
  "scenes": [
    {"prompt": "Scene 1 description..."},
    {"prompt": "Scene 2 description..."}
  ],
  "caption": "Your TikTok caption with #hashtags"
}`;

  // Attach the reference images so the story actually reflects them
  /* eslint-disable @typescript-eslint/no-explicit-any */
  const parts: any[] = [];
  for (const imagePath of imagePaths) {
    const buffer = await fs.readFile(imagePath);
    parts.push({
      inlineData: {
        mimeType: mimeTypeFor(imagePath),
        data: buffer.toString('base64'),
      },
    });
  }
  parts.push({ text: prompt });

  const model = process.env.GEMINI_TEXT_MODEL || 'gemini-3.5-flash';
  const { url, headers } = await getGenerateContentEndpoint(model);

  const response = await fetch(url, {
    method: 'POST',
    headers,
    body: JSON.stringify({
      contents: [{ role: 'user', parts }],
      generationConfig: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: 'OBJECT',
          properties: {
            narrationScript: { type: 'STRING' },
            scenes: {
              type: 'ARRAY',
              items: {
                type: 'OBJECT',
                properties: {
                  prompt: { type: 'STRING' },
                },
                required: ['prompt'],
              },
            },
            caption: { type: 'STRING' },
          },
          required: ['narrationScript', 'scenes', 'caption'],
        },
        temperature: 0.7,
      },
    }),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(
      `Story generation failed: ${response.status} ${errorText.slice(0, 300)}`,
    );
  }

  const json = (await response.json()) as Record<string, any>;
  const finishReason = json?.candidates?.[0]?.finishReason;
  const responseParts: any[] =
    json?.candidates?.[0]?.content?.parts ?? [];

  // Log full response structure for debugging
  console.log(`[story] Response finishReason=${finishReason}, parts=${responseParts.length}`);
  for (let i = 0; i < responseParts.length; i++) {
    const p = responseParts[i];
    const hasText = typeof p?.text === 'string';
    const isThought = !!p?.thought;
    console.log(`[story]   part[${i}]: thought=${isThought}, hasText=${hasText}, len=${hasText ? p.text.length : 0}`);
  }

  // Check for safety block or empty response
  if (finishReason === 'SAFETY' || responseParts.length === 0) {
    throw new Error(`Story generation blocked (finishReason=${finishReason}). The source text may contain content that triggers safety filters.`);
  }

  // Filter out thought parts (thinking models return parts with `thought: true`
  // for internal reasoning) and join only the actual output text parts.
  const outputParts = responseParts.filter((p) => !p?.thought);
  let text = outputParts
    .map((p) => (typeof p?.text === 'string' ? p.text : ''))
    .join('')
    .trim();

  // If all parts were thought parts, fall back to joining ALL parts
  if (!text) {
    console.warn('[story] All parts were thought parts or empty — joining all parts as fallback');
    text = responseParts
      .map((p) => (typeof p?.text === 'string' ? p.text : ''))
      .join('')
      .trim();
  }

  // Strip code fences
  if (text.startsWith('```')) {
    text = text.replace(/```json/g, '').replace(/```/g, '').trim();
  }

  console.log(`[story] Combined text (${text.length} chars): ${text.slice(0, 300)}…`);

  // Try multiple strategies to extract valid JSON
  let script: StoryScript | null = null;

  // Strategy 1: Direct parse
  try {
    script = JSON.parse(text) as StoryScript;
  } catch {
    // Strategy 2: Extract the first JSON object from mixed content
    // (thinking text might have leaked despite filtering)
    const jsonMatch = text.match(/\{[\s\S]*"narrationScript"[\s\S]*"scenes"[\s\S]*\}/);
    if (jsonMatch) {
      try {
        script = JSON.parse(jsonMatch[0]) as StoryScript;
        console.log('[story] Extracted JSON via regex from mixed content');
      } catch {
        // Strategy 3: Try each non-thought part individually
        for (const p of outputParts) {
          if (typeof p?.text === 'string') {
            let partText = p.text.trim();
            if (partText.startsWith('```')) {
              partText = partText.replace(/```json/g, '').replace(/```/g, '').trim();
            }
            try {
              script = JSON.parse(partText) as StoryScript;
              console.log('[story] Parsed JSON from individual part');
              break;
            } catch {
              continue;
            }
          }
        }
      }
    }
  }

  if (!script) {
    console.error(`[story] All JSON parse strategies failed. Raw text: ${text.slice(0, 1000)}`);
    throw new Error('Story generation returned invalid JSON');
  }

  if (!script.narrationScript || !Array.isArray(script.scenes) || script.scenes.length === 0) {
    throw new Error('Story generation returned an incomplete script');
  }

  console.log(
    `[story] Script generated (${script.scenes.length} scenes): ${script.narrationScript.slice(0, 100)}…`,
  );
  return script;
}

/**
 * Generate ONLY a narration script for presenter mode (talking-head video).
 * No scene prompts are produced — the caller constructs a uniform presenter
 * prompt for every segment.
 */
export async function generatePresenterScript(opts: {
  storyText: string;
  targetSeconds: number;
  segmentCount: number;
  personality?: string;
}): Promise<{ narrationScript: string; segments: string[]; caption?: string }> {
  const { storyText, targetSeconds, segmentCount, personality = 'social' } = opts;

  // Map each personality to its script-writing style instructions
  const personalityPrompts: Record<string, string> = {
    social:
      `Super casual and conversational — like someone filming themselves on their phone.\n` +
      `Use short punchy sentences, natural pauses, and direct address ("you", "look", "okay so").\n` +
      `Engaging and hook-driven — the first part should start with something attention-grabbing.\n` +
      `Informative but not stiff — explain things simply like talking to a friend.\n` +
      `Feel free to use filler words sparingly for authenticity ("like", "honestly", "basically").`,
    calm:
      `Calm, measured, and soothing — like a meditation guide or a thoughtful late-night radio host.\n` +
      `Use flowing, unhurried sentences with gentle transitions.\n` +
      `Speak as if sharing something meaningful over a quiet cup of tea.\n` +
      `Avoid exclamation marks, hype, or urgency. Let the ideas breathe.\n` +
      `The tone should feel grounding and reassuring throughout.`,
    pensive:
      `Reflective and thoughtful — like someone who has been turning an idea over in their mind.\n` +
      `Use contemplative phrasing with rhetorical questions and pauses for thought.\n` +
      `The speaker wonders aloud, considers different angles, and invites the viewer to think.\n` +
      `Avoid definitive statements — prefer "I wonder...", "What if...", "It makes you think...".\n` +
      `The mood is introspective, like a personal journal entry spoken aloud.`,
    happy:
      `Bright, cheerful, and genuinely delighted — like someone sharing exciting good news.\n` +
      `Use warm, upbeat language with a natural smile you can hear in the voice.\n` +
      `The speaker is enthusiastic without being over-the-top — think a friend who just discovered something wonderful.\n` +
      `Use positive framing and words that convey joy and optimism.\n` +
      `The energy is light and infectious throughout.`,
    energetic:
      `High-energy, fast-paced, and electrifying — like a sports commentator or hyped-up vlogger.\n` +
      `Use punchy, rapid-fire sentences with strong verbs and exclamatory emphasis.\n` +
      `Build momentum — each part should feel more exciting than the last.\n` +
      `The speaker is PUMPED about this topic and wants you to feel the same.\n` +
      `Think motivational speaker meets YouTube creator — raw enthusiasm and passion.`,
    serious:
      `Authoritative, measured, and no-nonsense — like a seasoned news anchor or documentary narrator.\n` +
      `Use precise, well-structured sentences with gravitas.\n` +
      `Avoid casual filler words or slang. Every word carries weight.\n` +
      `The speaker commands attention through credibility and composure.\n` +
      `Think 60 Minutes correspondent — professional, trustworthy, direct.`,
    witty:
      `Clever, dry, and subtly funny — like a witty essayist or a smart late-night monologue.\n` +
      `Weave in unexpected turns of phrase, gentle irony, and playful observations.\n` +
      `The humor is cerebral, not slapstick — the kind that makes you smirk and think.\n` +
      `Balance wit with substance — be entertaining AND informative.\n` +
      `The speaker is sharp and self-aware, occasionally breaking the fourth wall.`,
    warm:
      `Friendly, empathetic, and inviting — like a beloved teacher or a trusted older sibling.\n` +
      `Use inclusive language ("we", "us", "together") and speak with genuine care.\n` +
      `The speaker makes the viewer feel seen, understood, and welcome.\n` +
      `Avoid being preachy — this warmth comes from authenticity, not performance.\n` +
      `Think Mr. Rogers energy — kind, present, and genuinely interested.`,
    intense:
      `Passionate, driven, and urgent — like someone who feels this topic deeply and needs you to understand.\n` +
      `Use bold, declarative sentences with emotional weight.\n` +
      `The speaker leans in, makes eye contact, and speaks with conviction.\n` +
      `Build tension and release — some moments are quiet, others hit hard.\n` +
      `Think TED talk climax energy — the stakes feel real and personal.`,
  };

  const styleInstructions = personalityPrompts[personality] || personalityPrompts.social;

  const prompt = `You are writing a presenter script for a ${targetSeconds}-second talking-head video.

The video is filmed as exactly ${segmentCount} consecutive 8-second clips. Given the source text below, create:

1. The script, written as exactly ${segmentCount} parts — one part per 8-second clip:
- Each part MUST be between 15 and 20 words. This matters: fewer than 15 words leaves dead air in the clip, more than 20 words gets cut off before the person finishes speaking.
- Each part MUST consist only of complete sentences. A sentence must NEVER continue from one part into the next.
- Together the parts must read as one flowing, continuous monologue — no per-part greetings or restarts.
- ${styleInstructions}
- CRITICAL: The narration will be read aloud by a video model with strict content filters. \
The script MUST NOT mention: alcohol, alcoholism, drugs, drinking, drunkenness, guns, firearms, weapons, \
violence, aggression, injuries, death, crime, theft, sexual content, or any dangerous/harmful activities. \
If the source text covers these topics, either omit them entirely or reframe them in a safe, positive way.

2. A TikTok/social media caption (max 300 characters including hashtags). It should be attention-grabbing, \
informative, and include 3-5 relevant hashtags. Do NOT use generic hashtags like #fyp or #viral — use \
topic-specific ones drawn from the content.

Source text:
${storyText.slice(0, 6000)}

Return ONLY valid JSON (no markdown fences) with this structure:
{
  "segments": ["Part 1 text...", "Part 2 text..."],
  "caption": "Your TikTok caption with #hashtags"
}
The "segments" array must contain exactly ${segmentCount} strings.`;

  const model = process.env.GEMINI_TEXT_MODEL || 'gemini-3.5-flash';
  const { url, headers } = await getGenerateContentEndpoint(model);

  const response = await fetch(url, {
    method: 'POST',
    headers,
    body: JSON.stringify({
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: 'OBJECT',
          properties: {
            segments: {
              type: 'ARRAY',
              items: { type: 'STRING' },
            },
            caption: { type: 'STRING' },
          },
          required: ['segments', 'caption'],
        },
        temperature: 0.7,
      },
    }),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(
      `Presenter script generation failed: ${response.status} ${errorText.slice(0, 300)}`,
    );
  }

  /* eslint-disable @typescript-eslint/no-explicit-any */
  const json = (await response.json()) as Record<string, any>;
  const finishReason = json?.candidates?.[0]?.finishReason;
  const responseParts: any[] =
    json?.candidates?.[0]?.content?.parts ?? [];

  console.log(`[story] Presenter response finishReason=${finishReason}, parts=${responseParts.length}`);

  // Check for safety block or empty response
  if (finishReason === 'SAFETY' || responseParts.length === 0) {
    throw new Error(`Presenter script generation blocked (finishReason=${finishReason}). The source text may contain content that triggers safety filters.`);
  }

  // Filter out thought parts and join output text
  const outputParts = responseParts.filter((p) => !p?.thought);
  let text = outputParts
    .map((p) => (typeof p?.text === 'string' ? p.text : ''))
    .join('')
    .trim();

  if (!text) {
    console.warn('[story] Presenter: all parts were thought parts or empty — joining all parts as fallback');
    text = responseParts
      .map((p) => (typeof p?.text === 'string' ? p.text : ''))
      .join('')
      .trim();
  }

  // Strip code fences
  if (text.startsWith('```')) {
    text = text.replace(/```json/g, '').replace(/```/g, '').trim();
  }

  console.log(`[story] Presenter text (${text.length} chars): ${text.slice(0, 300)}…`);

  // Try multiple strategies to extract valid JSON
  type PresenterRaw = { segments?: string[]; narrationScript?: string; caption?: string };
  let result: PresenterRaw | null = null;

  // Strategy 1: Direct parse
  try {
    result = JSON.parse(text) as PresenterRaw;
  } catch {
    // Strategy 2: Extract JSON object via regex
    const jsonMatch = text.match(/\{[\s\S]*"(?:segments|narrationScript)"[\s\S]*\}/);
    if (jsonMatch) {
      try {
        result = JSON.parse(jsonMatch[0]) as PresenterRaw;
        console.log('[story] Presenter: extracted JSON via regex from mixed content');
      } catch {
        // Strategy 3: Try each non-thought part individually
        for (const p of outputParts) {
          if (typeof p?.text === 'string') {
            let partText = p.text.trim();
            if (partText.startsWith('```')) {
              partText = partText.replace(/```json/g, '').replace(/```/g, '').trim();
            }
            try {
              result = JSON.parse(partText) as PresenterRaw;
              console.log('[story] Presenter: parsed JSON from individual part');
              break;
            } catch {
              continue;
            }
          }
        }
      }
    }
  }

  if (!result) {
    console.error(`[story] Presenter: all JSON parse strategies failed. Raw text: ${text.slice(0, 1000)}`);
    throw new Error('Presenter script generation returned invalid JSON');
  }

  let segments = (result.segments ?? [])
    .filter((s): s is string => typeof s === 'string' && s.trim().length > 0)
    .map((s) => s.trim());

  // Fallback for a model that ignored the schema and returned one script blob
  if (segments.length === 0 && result.narrationScript) {
    segments = [result.narrationScript.trim()];
  }
  if (segments.length === 0) {
    throw new Error('Presenter script generation returned an incomplete script');
  }

  // If the model over-delivered, fold extras into the final part so no text is lost
  if (segments.length > segmentCount) {
    const extras = segments.splice(segmentCount - 1).join(' ');
    segments.push(extras);
  }

  const narrationScript = segments.join(' ');
  console.log(
    `[story] Presenter script generated (${segments.length}/${segmentCount} parts, ` +
      `${segments.map((s) => s.split(/\s+/).length).join('/')} words): ${narrationScript.slice(0, 100)}…`,
  );
  return { narrationScript, segments, caption: result.caption };
}

/** Deliberately safe fallback prompt for scenes rejected by the safety filter. */
export const SAFE_FALLBACK_SCENE =
  'A slow cinematic camera drift with abstract, softly lit shapes and gentle motion ' +
  'against a solid bright green chroma key screen background. Calm documentary mood. ' +
  'Ambient sound only. No people, no text, no dialogue.';

// ---------------------------------------------------------------------------
// Character profile auto-generation
// ---------------------------------------------------------------------------

/**
 * Given the user's pasted source text, use Gemini to suggest a fitting narrator
 * character profile — a short persona description that the TTS model can adopt.
 */
export async function generateCharacterProfile(storyText: string): Promise<string> {
  const model = process.env.GEMINI_TEXT_MODEL || 'gemini-3.5-flash';
  const { url, headers } = await getGenerateContentEndpoint(model);

  const prompt = `You are a casting director. Based on the source text below, write a narrator persona description for a documentary voice-over.

Cover these aspects in a single flowing paragraph:
- Background and expertise that makes this narrator credible for the subject matter
- Vocal qualities (pitch, timbre, any accent coloring)
- Pacing (speaking speed, use of pauses)
- Emotional tone (e.g. gravitas, warmth, curiosity, dry wit)
- Delivery style (e.g. intimate, authoritative, conversational)

Example:
"A seasoned foreign correspondent who has spent decades covering conflict zones. Speaks with quiet authority — unhurried, deliberate pacing with meaningful pauses between revelations. A deep, resonant baritone with traces of a mid-Atlantic accent. Emotionally restrained but not cold; conveys weight through understatement rather than dramatic emphasis."

Write exactly one paragraph, 3-5 sentences, roughly 50-100 words. Be vivid and specific.

Source text (excerpt):
${storyText.slice(0, 3000)}

Respond with ONLY a JSON object: {"profile": "your persona description here"}`;

  const response = await fetch(url, {
    method: 'POST',
    headers,
    body: JSON.stringify({
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: {
        responseMimeType: 'application/json',
        temperature: 0.7,
        maxOutputTokens: 2048,
      },
    }),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Character generation failed: ${response.status} ${errorText.slice(0, 200)}`);
  }

  /* eslint-disable @typescript-eslint/no-explicit-any */
  const json = (await response.json()) as Record<string, any>;
  const finishReason = json?.candidates?.[0]?.finishReason;
  const parts: any[] = json?.candidates?.[0]?.content?.parts ?? [];
  let text = parts
    .filter((p) => !p?.thought)
    .map((p) => (typeof p?.text === 'string' ? p.text : ''))
    .join('')
    .trim();

  if (!text) {
    throw new Error('Character generation returned empty response');
  }

  console.log(`[story] Character profile raw (${text.length} chars, finishReason=${finishReason}): ${text.slice(0, 200)}…`);

  // Strip code fences if present
  if (text.startsWith('```')) {
    text = text.replace(/```json/g, '').replace(/```/g, '').trim();
  }

  // Try full JSON parse first
  try {
    const parsed = JSON.parse(text) as { profile?: string };
    if (parsed.profile && typeof parsed.profile === 'string') {
      const profile = parsed.profile.trim();
      console.log(`[story] Character profile extracted (${profile.length} chars): ${profile.slice(0, 200)}…`);
      return profile;
    }
  } catch {
    console.warn('[story] Character profile JSON parse failed, attempting regex extraction');
  }

  // Fallback: extract the profile value via regex even from truncated JSON
  // e.g. {"profile": "An intrepid explorer who...   (cut off before closing quote/brace)
  const profileMatch = text.match(/"profile"\s*:\s*"((?:[^"\\]|\\.)*)("?)/s);
  if (profileMatch) {
    const extracted = profileMatch[1]
      .replace(/\\n/g, ' ')
      .replace(/\\"/g, '"')
      .replace(/\\\\/g, '\\')
      .trim();
    if (extracted.length > 10) {
      console.log(`[story] Character profile regex-extracted (${extracted.length} chars): ${extracted.slice(0, 200)}…`);
      return extracted;
    }
  }

  // Last resort: strip all JSON artifacts and return whatever text remains
  const cleaned = text
    .replace(/^\s*\{\s*"profile"\s*:\s*"?/i, '')
    .replace(/"?\s*\}\s*$/, '')
    .replace(/\\n/g, ' ')
    .replace(/\\"/g, '"')
    .trim();

  console.log(`[story] Character profile last-resort cleanup (${cleaned.length} chars): ${cleaned.slice(0, 200)}…`);
  return cleaned || text;
}

// ---------------------------------------------------------------------------
// Music prompt suggestion
// ---------------------------------------------------------------------------

/**
 * Given the user's pasted source text, use Gemini to suggest a fitting
 * music prompt — a short description of ideal background music.
 */
export async function generateMusicPrompt(storyText: string): Promise<string> {
  const model = process.env.GEMINI_TEXT_MODEL || 'gemini-3.5-flash';
  const { url, headers } = await getGenerateContentEndpoint(model);

  const prompt = `Based on the following story text, write a short (1-2 sentence) music prompt describing the ideal instrumental background music for a video narration. Focus on mood, tempo, instruments, and genre. No vocals or lyrics. Be specific and evocative.

Source text (excerpt):
${storyText.slice(0, 3000)}

Respond with ONLY a JSON object: {"musicPrompt": "your music description here"}`;

  const response = await fetch(url, {
    method: 'POST',
    headers,
    body: JSON.stringify({
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: {
        responseMimeType: 'application/json',
        temperature: 0.7,
        maxOutputTokens: 1024,
      },
    }),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Music prompt generation failed: ${response.status} ${errorText.slice(0, 200)}`);
  }

  /* eslint-disable @typescript-eslint/no-explicit-any */
  const json = (await response.json()) as Record<string, any>;
  const parts: any[] = json?.candidates?.[0]?.content?.parts ?? [];
  let text = parts
    .filter((p) => !p?.thought)
    .map((p) => (typeof p?.text === 'string' ? p.text : ''))
    .join('')
    .trim();

  if (!text) {
    throw new Error('Music prompt generation returned empty response');
  }

  // Strip code fences if present
  if (text.startsWith('```')) {
    text = text.replace(/```json/g, '').replace(/```/g, '').trim();
  }

  // Try full JSON parse first
  try {
    const parsed = JSON.parse(text) as { musicPrompt?: string };
    if (parsed.musicPrompt && typeof parsed.musicPrompt === 'string') {
      return parsed.musicPrompt.trim();
    }
  } catch {
    console.warn('[story] Music prompt JSON parse failed, attempting regex extraction');
  }

  // Fallback: extract the musicPrompt value via regex
  const promptMatch = text.match(/"musicPrompt"\s*:\s*"((?:[^"\\]|\\.)*)("?)/s);
  if (promptMatch) {
    const extracted = promptMatch[1]
      .replace(/\\n/g, ' ')
      .replace(/\\"/g, '"')
      .replace(/\\\\/g, '\\')
      .trim();
    if (extracted.length > 5) {
      return extracted;
    }
  }

  // Last resort: strip all JSON artifacts
  const cleaned = text
    .replace(/^\s*\{\s*"musicPrompt"\s*:\s*"?/i, '')
    .replace(/"?\s*\}\s*$/, '')
    .replace(/\\n/g, ' ')
    .replace(/\\"/g, '"')
    .trim();

  return cleaned || text;
}
